 26Ôćĺ/// State of an MCP client connection.
 27Ôćĺ#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 28Ôćĺpub enum McpClientState {
 29Ôćĺ    /// Transport spawned, not yet initialized.
 30Ôćĺ    Connected,
 31Ôćĺ    /// `initialize` completed, `initialized` notification sent.
 32Ôćĺ    Ready,
 33Ôćĺ    /// OAuth authentication in progress (waiting for browser).
 34Ôćĺ    Authenticating,
 35Ôćĺ    /// Server process exited or was shut down.
 36Ôćĺ    Closed,
 37Ôćĺ}
