 39Ôćĺ/// An MCP client connected to a single server via stdio.
 40Ôćĺpub struct McpClient {
 41Ôćĺ    server_name: String,
 42Ôćĺ    transport: Arc<dyn McpTransport>,
 43Ôćĺ    state: McpClientState,
 44Ôćĺ    server_info: Option<InitializeResult>,
 45Ôćĺ    tools: Vec<McpToolDef>,
 46Ôćĺ}
