 48Ôćĺimpl McpClient {
 49Ôćĺ    /// Spawn the server process and perform the MCP handshake (initialize + initialized).
 50Ôćĺ    pub async fn connect(
 51Ôćĺ        server_name: &str,
 52Ôćĺ        command: &str,
 53Ôćĺ        args: &[String],
 54Ôćĺ        env: &HashMap<String, String>,
 55Ôćĺ        request_timeout: Duration,
 56Ôćĺ    ) -> Result<Self> {
 57Ôćĺ        info!(server = %server_name, command = %command, args = ?args, "connecting to MCP server");
 58Ôćĺ        let transport =
 59Ôćĺ            StdioTransport::spawn_with_timeout(command, args, env, request_timeout).await?;
 60Ôćĺ
 61Ôćĺ        let mut client = Self {
 62Ôćĺ            server_name: server_name.into(),
 63Ôćĺ            transport,
 64Ôćĺ            state: McpClientState::Connected,
 65Ôćĺ            server_info: None,
 66Ôćĺ            tools: Vec::new(),
 67Ôćĺ        };
 68Ôćĺ
 69Ôćĺ        if let Err(e) = client.initialize().await {
 70Ôćĺ            warn!(server = %server_name, error = %e, "MCP initialize handshake failed");
 71Ôćĺ            return Err(e);
 72Ôćĺ        }
 73Ôćĺ
 74Ôćĺ        // Track MCP server connection
 75Ôćĺ        #[cfg(feature = "metrics")]
 76Ôćĺ        {
 77Ôćĺ            counter!(mcp_metrics::SERVER_CONNECTIONS_TOTAL, labels::SERVER => server_name.to_string())
 78Ôćĺ                .increment(1);
 79Ôćĺ            gauge!(mcp_metrics::SERVERS_CONNECTED).increment(1.0);
 80Ôćĺ        }
 81Ôćĺ
 82Ôćĺ        Ok(client)
 83Ôćĺ    }
