  2Ôćĺ//!
  3Ôćĺ//! Adapts [`McpToolBridge`](moltis_mcp::tool_bridge::McpToolBridge) (mcp crate)
  4Ôćĺ//! to [`AgentTool`] (agents crate) and provides sync logic to register MCP tools
  5Ôćĺ//! into a [`ToolRegistry`].
  6Ôćĺ
  7Ôćĺuse std::sync::Arc;
  8Ôćĺ
  9Ôćĺuse {async_trait::async_trait, tokio::sync::RwLock};
 10Ôćĺ
 11Ôćĺ#[cfg(feature = "tracing")]
 12Ôćĺuse tracing::info;
 13Ôćĺ
 14Ôćĺuse {
 15Ôćĺ    moltis_agents::tool_registry::{AgentTool, ToolRegistry},
 16Ôćĺ    moltis_mcp::tool_bridge::{McpAgentTool, McpToolBridge},
 17Ôćĺ};
 18Ôćĺ
 19Ôćĺ/// Thin adapter that implements `AgentTool` (agents crate) by delegating to
 20Ôćĺ/// `McpToolBridge` which implements `McpAgentTool` (mcp crate).
 21Ôćĺpub struct McpToolAdapter(pub McpToolBridge);
 22Ôćĺ
 23Ôćĺ#[async_trait]
 24Ôćĺimpl AgentTool for McpToolAdapter {
 25Ôćĺ    fn name(&self) -> &str {
 26Ôćĺ        McpAgentTool::name(&self.0)
 27Ôćĺ    }
 28Ôćĺ
 29Ôćĺ    fn description(&self) -> &str {
 30Ôćĺ        McpAgentTool::description(&self.0)
 31Ôćĺ    }
 32Ôćĺ
 33Ôćĺ    fn parameters_schema(&self) -> serde_json::Value {
 34Ôćĺ        McpAgentTool::parameters_schema(&self.0)
 35Ôćĺ    }
 36Ôćĺ
 37Ôćĺ    async fn execute(&self, params: serde_json::Value) -> anyhow::Result<serde_json::Value> {
 38Ôćĺ        McpAgentTool::execute(&self.0, params)
 39Ôćĺ            .await
 40Ôćĺ            .map_err(anyhow::Error::from)
 41Ôćĺ    }
 42Ôćĺ}
 43Ôćĺ
 44Ôćĺ/// Synchronize MCP tool bridges into the shared [`ToolRegistry`].
 45Ôćĺ///
 46Ôćĺ/// Removes all existing `mcp__*` tools and re-registers current bridges.
 47Ôćĺ#[cfg_attr(feature = "tracing", tracing::instrument(skip_all, fields(tool_count)))]
 48Ôćĺpub async fn sync_mcp_tools(
 49Ôćĺ    manager: &moltis_mcp::McpManager,
 50Ôćĺ    registry: &Arc<RwLock<ToolRegistry>>,
 51Ôćĺ) {
 52Ôćĺ    let bridges = manager.tool_bridges().await;
 53Ôćĺ
 54Ôćĺ    let mut reg = registry.write().await;
 55Ôćĺ
 56Ôćĺ    // Remove all MCP-sourced tools before re-registering current ones.
 57Ôćĺ    reg.unregister_mcp();
 58Ôćĺ
 59Ôćĺ    // Register current bridges with their server name metadata.
 60Ôćĺ    let count = bridges.len();
 61Ôćĺ    for bridge in bridges {
 62Ôćĺ        let server = bridge.server_name().to_string();
 63Ôćĺ        reg.register_mcp(Box::new(McpToolAdapter(bridge)), server);
 64Ôćĺ    }
 65Ôćĺ
 66Ôćĺ    #[cfg(feature = "tracing")]
 67Ôćĺ    if count > 0 {
 68Ôćĺ        info!(tools = count, "MCP tools synced into tool registry");
 69Ôćĺ    }
 70Ôćĺ}
