  1Ôćĺ//! Import MCP server configuration from OpenClaw.
  2Ôćĺ//!
  3Ôćĺ//! Merges OpenClaw's `mcp-servers.json` into Moltis's MCP registry,
  4Ôćĺ//! skipping servers with duplicate names.
  5Ôćĺ
  6Ôćĺuse std::{collections::HashMap, path::Path};
  7Ôćĺ
  8Ôćĺuse tracing::debug;
  9Ôćĺ
 10Ôćĺuse crate::{
 11Ôćĺ    detect::OpenClawDetection,
 12Ôćĺ    report::{CategoryReport, ImportCategory, ImportStatus},
 13Ôćĺ    types::OpenClawMcpServer,
 14Ôćĺ};
 15Ôćĺ
 16Ôćĺ/// Import MCP servers from OpenClaw into the Moltis MCP registry.
 17Ôćĺ///
 18Ôćĺ/// `dest_mcp_path` is the path to Moltis's `mcp-servers.json`.
 19Ôćĺpub fn import_mcp_servers(detection: &OpenClawDetection, dest_mcp_path: &Path) -> CategoryReport {
 20Ôćĺ    let src_path = detection.home_dir.join("mcp-servers.json");
 21Ôćĺ    if !src_path.is_file() {
 22Ôćĺ        return CategoryReport::skipped(ImportCategory::McpServers);
 23Ôćĺ    }
 24Ôćĺ
 25Ôćĺ    let src_servers = match load_mcp_servers(&src_path) {
 26Ôćĺ        Ok(s) => s,
 27Ôćĺ        Err(e) => {
 28Ôćĺ            return CategoryReport::failed(
 29Ôćĺ                ImportCategory::McpServers,
 30Ôćĺ                format!("failed to parse OpenClaw mcp-servers.json: {e}"),
 31Ôćĺ            );
 32Ôćĺ        },
 33Ôćĺ    };
 34Ôćĺ
 35Ôćĺ    if src_servers.is_empty() {
 36Ôćĺ        return CategoryReport::skipped(ImportCategory::McpServers);
 37Ôćĺ    }
 38Ôćĺ
 39Ôćĺ    // Load existing Moltis MCP servers
 40Ôćĺ    let mut existing = if dest_mcp_path.is_file() {
 41Ôćĺ        load_mcp_servers(dest_mcp_path).unwrap_or_default()
 42Ôćĺ    } else {
 43Ôćĺ        HashMap::new()
 44Ôćĺ    };
 45Ôćĺ
 46Ôćĺ    let mut imported = 0;
 47Ôćĺ    let mut skipped = 0;
 48Ôćĺ
 49Ôćĺ    for (name, server) in &src_servers {
 50Ôćĺ        if existing.contains_key(name) {
 51Ôćĺ            debug!(name, "MCP server already exists, skipping");
 52Ôćĺ            skipped += 1;
 53Ôćĺ            continue;
 54Ôćĺ        }
 55Ôćĺ
 56Ôćĺ        debug!(name, command = %server.command, "importing MCP server");
 57Ôćĺ        existing.insert(name.clone(), server.clone());
 58Ôćĺ        imported += 1;
 59Ôćĺ    }
 60Ôćĺ
 61Ôćĺ    if imported > 0 {
 62Ôćĺ        if let Some(parent) = dest_mcp_path.parent()
 63Ôćĺ            && let Err(e) = std::fs::create_dir_all(parent)
 64Ôćĺ        {
 65Ôćĺ            return CategoryReport::failed(
 66Ôćĺ                ImportCategory::McpServers,
 67Ôćĺ                format!("failed to create directory: {e}"),
 68Ôćĺ            );
 69Ôćĺ        }
 70Ôćĺ        let json = match serde_json::to_string_pretty(&existing) {
 71Ôćĺ            Ok(j) => j,
 72Ôćĺ            Err(e) => {
 73Ôćĺ                return CategoryReport::failed(
 74Ôćĺ                    ImportCategory::McpServers,
 75Ôćĺ                    format!("failed to serialize MCP servers: {e}"),
 76Ôćĺ                );
 77Ôćĺ            },
 78Ôćĺ        };
 79Ôćĺ        if let Err(e) = std::fs::write(dest_mcp_path, json) {
 80Ôćĺ            return CategoryReport::failed(
 81Ôćĺ                ImportCategory::McpServers,
 82Ôćĺ                format!("failed to write mcp-servers.json: {e}"),
 83Ôćĺ            );
 84Ôćĺ        }
 85Ôćĺ    }
 86Ôćĺ
 87Ôćĺ    let status = if imported == 0 {
 88Ôćĺ        ImportStatus::Skipped
 89Ôćĺ    } else {
 90Ôćĺ        ImportStatus::Success
 91Ôćĺ    };
 92Ôćĺ
 93Ôćĺ    CategoryReport {
 94Ôćĺ        category: ImportCategory::McpServers,
 95Ôćĺ        status,
 96Ôćĺ        items_imported: imported,
 97Ôćĺ        items_updated: 0,
 98Ôćĺ        items_skipped: skipped,
 99Ôćĺ        warnings: Vec::new(),
100Ôćĺ        errors: Vec::new(),

