  1Ôćĺconst { expect } = require("@playwright/test");
  2Ôćĺ
  3Ôćĺ/**
  4Ôćĺ * Wait until the SPA has mounted visible content into #pageContent.
  5Ôćĺ * This is a stable cross-route readiness signal for the app shell.
  6Ôćĺ */
  7Ôćĺasync function expectPageContentMounted(page) {
  8Ôćĺ	await expect
  9Ôćĺ		.poll(
 10Ôćĺ			async () => {
 11Ôćĺ				try {
 12Ôćĺ					return await page.evaluate(() => {
 13Ôćĺ						const el = document.getElementById("pageContent");
 14Ôćĺ						if (!el) return 0;
 15Ôćĺ						return el.childElementCount;
 16Ôćĺ					});
 17Ôćĺ				} catch (error) {
 18Ôćĺ					if (isRetryableNavigationError(error)) return 0;
 19Ôćĺ					throw error;
 20Ôćĺ				}
 21Ôćĺ			},
 22Ôćĺ			{
 23Ôćĺ				timeout: 20_000,
 24Ôćĺ			},
 25Ôćĺ		)
 26Ôćĺ		.toBeGreaterThan(0);
 27Ôćĺ}
 28Ôćĺ
 29Ôćĺ/**
 30Ôćĺ * Collect uncaught page errors for later assertion.
 31Ôćĺ * Returns an array that fills as errors occur.
 32Ôćĺ *
 33Ôćĺ * Usage:
 34Ôćĺ *   const pageErrors = watchPageErrors(page);
 35Ôćĺ *   // ... interact with page ...
 36Ôćĺ *   expect(pageErrors).toEqual([]);
 37Ôćĺ */
 38Ôćĺfunction watchPageErrors(page) {
 39Ôćĺ	const pageErrors = [];
 40Ôćĺ	page.on("pageerror", (err) => pageErrors.push(err.message));
 41Ôćĺ	return pageErrors;
 42Ôćĺ}
 43Ôćĺ
 44Ôćĺ/**
 45Ôćĺ * Wait for the WebSocket connection status dot to reach "connected".
 46Ôćĺ * Note: #statusText is intentionally set to "" when connected, so we
 47Ôćĺ * only check the dot's CSS class.
 48Ôćĺ */
 49Ôćĺasync function waitForWsConnected(page, timeoutMs = 20_000) {
 50Ôćĺ	await expect
 51Ôćĺ		.poll(
 52Ôćĺ			async () => {
 53Ôćĺ				const statusDotConnected = await page
 54Ôćĺ					.locator("#statusDot")
 55Ôćĺ					.getAttribute("class")
 56Ôćĺ					.then((cls) => /connected/.test(cls || ""))
 57Ôćĺ					.catch(() => false);
 58Ôćĺ				if (!statusDotConnected) return false;
 59Ôćĺ				return page
 60Ôćĺ					.evaluate(async () => {
 61Ôćĺ						const appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 62Ôćĺ						if (!appScript) return false;
 63Ôćĺ						const appUrl = new URL(appScript.src, window.location.origin);
 64Ôćĺ						const prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 65Ôćĺ						const state = await import(`${prefix}js/state.js`);
 66Ôćĺ						return Boolean(state.connected && state.ws && state.ws.readyState === WebSocket.OPEN);
 67Ôćĺ					})
 68Ôćĺ					.catch(() => false);
 69Ôćĺ			},
 70Ôćĺ			{ timeout: timeoutMs },
 71Ôćĺ		)
 72Ôćĺ		.toBe(true);
 73Ôćĺ}
 74Ôćĺ
 75Ôćĺfunction isRetryableNavigationError(error) {
 76Ôćĺ	var message = error?.message || String(error || "");
 77Ôćĺ	return (
 78Ôćĺ		message.includes("net::ERR_ABORTED") ||
 79Ôćĺ		message.includes("Execution context was destroyed") ||
 80Ôćĺ		message.includes("Target page, context or browser has been closed")
 81Ôćĺ	);
 82Ôćĺ}
 83Ôćĺ
 84Ôćĺ/**
 85Ôćĺ * Navigate to a path, wait for SPA content to mount, and assert no errors.
 86Ôćĺ * Returns the pageErrors array for further assertions.
 87Ôćĺ */
 88Ôćĺasync function navigateAndWait(page, path) {
 89Ôćĺ	const pageErrors = watchPageErrors(page);
 90Ôćĺ	let lastError = null;
 91Ôćĺ	for (let attempt = 0; attempt < 3; attempt++) {
 92Ôćĺ		try {
 93Ôćĺ			await page.goto(path, { waitUntil: "domcontentloaded" });
 94Ôćĺ			await expectPageContentMounted(page);
 95Ôćĺ			return pageErrors;
 96Ôćĺ		} catch (error) {
 97Ôćĺ			lastError = error;
 98Ôćĺ			if (!isRetryableNavigationError(error) || attempt === 2) {
 99Ôćĺ				break;
100Ôćĺ			}
101Ôćĺ		}
102Ôćĺ	}
103Ôćĺ	if (lastError) throw lastError;
104Ôćĺ	return pageErrors;
105Ôćĺ}
