107Ôćĺ/**
108Ôćĺ * Create a new session by clicking the new-session button.
109Ôćĺ * Waits for the active key to change, URL to update, and content to mount.
110Ôćĺ *
111Ôćĺ * Note: we intentionally do NOT wait for the session to appear in the
112Ôćĺ * sessions list (store.getByKey). The list is populated asynchronously
113Ôćĺ * by the sessions.switch RPC and can be slow under heavy test load.
114Ôćĺ * The key change + URL match + page mount are sufficient to prove the
115Ôćĺ * session was created; individual tests can wait for store indexing
116Ôćĺ * if their assertions require it.
117Ôćĺ */
118Ôćĺasync function createSession(page) {
119Ôćĺ	const timeoutMs = 20_000;
120Ôćĺ	const previousActiveKey = await page.evaluate(() => {
121Ôćĺ		return window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
122Ôćĺ	});
123Ôćĺ
124Ôćĺ	await page.locator("#newSessionBtn").click();
125Ôćĺ	await expect
126Ôćĺ		.poll(
127Ôćĺ			() =>
128Ôćĺ				page.evaluate(() => {
129Ôćĺ					return window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
130Ôćĺ				}),
131Ôćĺ			{ timeout: timeoutMs },
132Ôćĺ		)
133Ôćĺ		.not.toBe(previousActiveKey);
134Ôćĺ
135Ôćĺ	await expect
136Ôćĺ		.poll(
137Ôćĺ			() =>
138Ôćĺ				page.evaluate(() => {
139Ôćĺ					const key = window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
140Ôćĺ					if (!key) return false;
141Ôćĺ					return window.location.pathname === `/chats/${key.replace(/:/g, "/")}`;
142Ôćĺ				}),
143Ôćĺ			{ timeout: timeoutMs },
144Ôćĺ		)
145Ôćĺ		.toBe(true);
146Ôćĺ
147Ôćĺ	await expectPageContentMounted(page);
148Ôćĺ}
