 1Ôćĺ// Shared Playwright test fixture with automatic error-context capture.
 2Ôćĺ//
 3Ôćĺ// Every spec file should import { test, expect } from this module instead of
 4Ôćĺ// from "@playwright/test".  On failure the fixture attaches a markdown
 5Ôćĺ// snapshot of every open page (URL, title, visible text) so CI logs contain
 6Ôćĺ// enough context to diagnose failures without downloading trace artifacts.
 7Ôćĺ
 8Ôćĺconst { test: base, expect } = require("@playwright/test");
 9Ôćĺ
10Ôćĺvar test = base.extend({
11Ôćĺ	page: async ({ page, context }, use, testInfo) => {
12Ôćĺ		await use(page);
13Ôćĺ
14Ôćĺ		if (testInfo.status !== testInfo.expectedStatus) {
15Ôćĺ			var pages = context.pages();
16Ôćĺ			var parts = [];
17Ôćĺ
18Ôćĺ			for (var i = 0; i < pages.length; i++) {
19Ôćĺ				var p = pages[i];
20Ôćĺ				try {
21Ôćĺ					if (p.isClosed()) {
22Ôćĺ						parts.push(`### Page ${i + 1}: (closed)`);
23Ôćĺ						continue;
24Ôćĺ					}
25Ôćĺ					var url = p.url();
26Ôćĺ					var title = await p.title().catch(() => "(unknown)");
27Ôćĺ					var text = await p
28Ôćĺ						.evaluate(() => document.body?.innerText?.slice(0, 3000) || "")
29Ôćĺ						.catch(() => "(unavailable)");
30Ôćĺ					parts.push(`### Page ${i + 1}: ${title}\n- **URL**: ${url}\n\n\`\`\`\n${text}\n\`\`\``);
31Ôćĺ				} catch {
32Ôćĺ					parts.push(`### Page ${i + 1}: (error reading page)`);
33Ôćĺ				}
34Ôćĺ			}
35Ôćĺ
36Ôćĺ			var md = ["## Error Context", "", `**Test**: ${testInfo.title}`, `**Status**: ${testInfo.status}`, ""]
37Ôćĺ				.concat(parts)
38Ôćĺ				.join("\n");
39Ôćĺ
40Ôćĺ			await testInfo.attach("error-context", {
41Ôćĺ				body: Buffer.from(md, "utf-8"),
42Ôćĺ				contentType: "text/markdown",
43Ôćĺ			});
44Ôćĺ		}
45Ôćĺ	},
46Ôćĺ});
47Ôćĺ
48Ôćĺmodule.exports = { test, expect };
