 60Ôćĺfunction handleAuthorize(res, query) {
 61Ôćĺ	if (!(query.client_id && query.redirect_uri && query.code_challenge && query.state)) {
 62Ôćĺ		return respond(res, 400, {
 63Ôćĺ			error: "invalid_request",
 64Ôćĺ			error_description: "Missing required parameters: client_id, redirect_uri, code_challenge, state",
 65Ôćĺ		});
 66Ôćĺ	}
 67Ôćĺ	if (query.code_challenge_method !== "S256") {
 68Ôćĺ		return respond(res, 400, {
 69Ôćĺ			error: "invalid_request",
 70Ôćĺ			error_description: "Only S256 code_challenge_method is supported",
 71Ôćĺ		});
 72Ôćĺ	}
 73Ôćĺ
 74Ôćĺ	pendingFlows.set(query.state, {
 75Ôćĺ		challenge: query.code_challenge,
 76Ôćĺ		redirectUri: query.redirect_uri,
 77Ôćĺ	});
 78Ôćĺ
 79Ôćĺ	var authCode = `mock-auth-code-${crypto.randomBytes(8).toString("hex")}`;
 80Ôćĺ	issuedCodes.set(authCode, { state: query.state });
 81Ôćĺ
 82Ôćĺ	var redirectUrl = new URL(query.redirect_uri);
 83Ôćĺ	redirectUrl.searchParams.set("code", authCode);
 84Ôćĺ	redirectUrl.searchParams.set("state", query.state);
 85Ôćĺ	lastRedirectUrl = redirectUrl.toString();
 86Ôćĺ
 87Ôćĺ	if (authorizeShouldNotRedirect) {
 88Ôćĺ		return respond(res, 200, {
 89Ôćĺ			ok: true,
 90Ôćĺ			note: "authorize_should_not_redirect is enabled",
 91Ôćĺ			redirect_url: lastRedirectUrl,
 92Ôćĺ		});
 93Ôćĺ	}
 94Ôćĺ
 95Ôćĺ	res.writeHead(302, { Location: redirectUrl.toString() });
 96Ôćĺ	res.end();
 97Ôćĺ}
