 99Ôćĺfunction handleTokenExchange(res, body) {
100Ôćĺ	var authCode = body.get("code");
101Ôćĺ	var verifier = body.get("code_verifier");
102Ôćĺ	var clientId = body.get("client_id");
103Ôćĺ
104Ôćĺ	if (!(authCode && verifier && clientId)) {
105Ôćĺ		return respond(res, 400, {
106Ôćĺ			error: "invalid_request",
107Ôćĺ			error_description: "Missing code, code_verifier, or client_id",
108Ôćĺ		});
109Ôćĺ	}
110Ôćĺ
111Ôćĺ	var codeEntry = issuedCodes.get(authCode);
112Ôćĺ	if (!codeEntry) {
113Ôćĺ		return respond(res, 400, {
114Ôćĺ			error: "invalid_grant",
115Ôćĺ			error_description: "Unknown or expired authorization code",
116Ôćĺ		});
117Ôćĺ	}
118Ôćĺ
119Ôćĺ	var flow = pendingFlows.get(codeEntry.state);
120Ôćĺ	if (!flow) {
121Ôćĺ		return respond(res, 400, {
122Ôćĺ			error: "invalid_grant",
123Ôćĺ			error_description: "No pending flow for this state",
124Ôćĺ		});
125Ôćĺ	}
126Ôćĺ
127Ôćĺ	if (!verifyPkce(verifier, flow.challenge)) {
128Ôćĺ		return respond(res, 400, {
129Ôćĺ			error: "invalid_grant",
130Ôćĺ			error_description: "PKCE verification failed",
131Ôćĺ		});
132Ôćĺ	}
133Ôćĺ
134Ôćĺ	issuedCodes.delete(authCode);
135Ôćĺ	pendingFlows.delete(codeEntry.state);
136Ôćĺ
137Ôćĺ	return respond(res, 200, {
138Ôćĺ		access_token: `mock-access-token-${crypto.randomBytes(8).toString("hex")}`,
139Ôćĺ		refresh_token: `mock-refresh-token-${crypto.randomBytes(8).toString("hex")}`,
140Ôćĺ		token_type: "Bearer",
141Ôćĺ		expires_in: 3600,
142Ôćĺ	});
143Ôćĺ}
144Ôćĺ
145Ôćĺfunction handleTokenRefresh(res, body) {
146Ôćĺ	var refreshToken = body.get("refresh_token");
147Ôćĺ	if (!refreshToken) {
148Ôćĺ		return respond(res, 400, {
149Ôćĺ			error: "invalid_request",
150Ôćĺ			error_description: "Missing refresh_token",
151Ôćĺ		});
152Ôćĺ	}
153Ôćĺ
154Ôćĺ	return respond(res, 200, {
155Ôćĺ		access_token: `mock-refreshed-token-${crypto.randomBytes(8).toString("hex")}`,
156Ôćĺ		refresh_token: `mock-refresh-token-${crypto.randomBytes(8).toString("hex")}`,
157Ôćĺ		token_type: "Bearer",
158Ôćĺ		expires_in: 3600,
159Ôćĺ	});
160Ôćĺ}
161Ôćĺ
162Ôćĺasync function handleToken(res, req) {
163Ôćĺ	var body = await parseBody(req);
164Ôćĺ	var grantType = body.get("grant_type");
165Ôćĺ
166Ôćĺ	if (tokenShouldFail) {
167Ôćĺ		return respond(res, 400, {
168Ôćĺ			error: "server_error",
169Ôćĺ			error_description: "Mock server configured to return errors",
170Ôćĺ		});
171Ôćĺ	}
172Ôćĺ
173Ôćĺ	if (grantType === "authorization_code") {
174Ôćĺ		return handleTokenExchange(res, body);
175Ôćĺ	}
176Ôćĺ	if (grantType === "refresh_token") {
177Ôćĺ		return handleTokenRefresh(res, body);
178Ôćĺ	}
179Ôćĺ
180Ôćĺ	return respond(res, 400, {
181Ôćĺ		error: "unsupported_grant_type",
182Ôćĺ		error_description: `Unsupported grant_type: ${grantType}`,
183Ôćĺ	});
184Ôćĺ}
185Ôćĺ
186Ôćĺasync function handleConfig(req) {
187Ôćĺ	var configBody = await parseBody(req);
188Ôćĺ	if (configBody.has("token_should_fail")) {
189Ôćĺ		tokenShouldFail = configBody.get("token_should_fail") === "true";
190Ôćĺ	}
191Ôćĺ	if (configBody.has("authorize_should_not_redirect")) {
192Ôćĺ		authorizeShouldNotRedirect = configBody.get("authorize_should_not_redirect") === "true";
193Ôćĺ	}
194Ôćĺ}
