196Ôćĺfunction handleReset() {
197Ôćĺ	calls = [];
198Ôćĺ	pendingFlows.clear();
199Ôćĺ	issuedCodes.clear();
200Ôćĺ	tokenShouldFail = false;
201Ôćĺ	authorizeShouldNotRedirect = false;
202Ôćĺ	lastRedirectUrl = null;
203Ôćĺ}
204Ôćĺ
205Ôćĺvar server = http.createServer(async (req, res) => {
206Ôćĺ	var parsed = parseRequestUrl(req);
207Ôćĺ	var pathname = parsed.pathname;
208Ôćĺ	var query = queryObject(parsed.searchParams);
209Ôćĺ
210Ôćĺ	calls.push({
211Ôćĺ		method: req.method,
212Ôćĺ		path: pathname,
213Ôćĺ		query,
214Ôćĺ		timestamp: Date.now(),
215Ôćĺ	});
216Ôćĺ
217Ôćĺ	if (req.method === "GET" && pathname === "/authorize") {
218Ôćĺ		return handleAuthorize(res, query);
219Ôćĺ	}
220Ôćĺ	if (req.method === "POST" && pathname === "/token") {
221Ôćĺ		return handleToken(res, req);
222Ôćĺ	}
223Ôćĺ	if (req.method === "GET" && pathname === "/calls") {
224Ôćĺ		return respond(res, 200, calls);
225Ôćĺ	}
226Ôćĺ	if (req.method === "GET" && pathname === "/last-redirect") {
227Ôćĺ		return respond(res, 200, { redirect_url: lastRedirectUrl });
