 13Ôćĺ/// Recursively strip null values from nested objects and arrays.
 14Ôćĺ///
 15Ôćĺ/// Top-level null stripping is handled by the caller; this recurses into
 16Ôćĺ/// values that are themselves objects or arrays.
 17Ôćĺfn strip_nulls_recursive(map: &mut serde_json::Map<String, serde_json::Value>) {
 18Ôćĺ    for value in map.values_mut() {
 19Ôćĺ        match value {
 20Ôćĺ            serde_json::Value::Object(inner) => {
 21Ôćĺ                inner.retain(|_, v| !v.is_null());
 22Ôćĺ                strip_nulls_recursive(inner);
 23Ôćĺ            },
 24Ôćĺ            serde_json::Value::Array(arr) => {
 25Ôćĺ                for item in arr.iter_mut() {
 26Ôćĺ                    if let serde_json::Value::Object(inner) = item {
 27Ôćĺ                        inner.retain(|_, v| !v.is_null());
 28Ôćĺ                        strip_nulls_recursive(inner);
 29Ôćĺ                    }
 30Ôćĺ                }
 31Ôćĺ            },
 32Ôćĺ            _ => {},
 33Ôćĺ        }
 34Ôćĺ    }
 35Ôćĺ}
