 44Ôćĺ    server_name: String,
 45Ôćĺ    description: String,
 46Ôćĺ    input_schema: serde_json::Value,
 47Ôćĺ    client: Arc<tokio::sync::RwLock<dyn McpClientTrait>>,
 48Ôćĺ}
