 92Ôćĺ/// Trait for agent-callable tools, matching `AgentTool` in moltis-agents.
 93Ôćĺ///
 94Ôćĺ/// We define our own copy here to avoid a circular dependency on moltis-agents.
 95Ôćĺ/// The gateway wires `McpToolBridge` into the `ToolRegistry` via a thin adapter.
 96Ôćĺ#[async_trait]
 97Ôćĺpub trait McpAgentTool: Send + Sync {
 98Ôćĺ    fn name(&self) -> &str;
 99Ôćĺ    fn description(&self) -> &str;
100Ôćĺ    fn parameters_schema(&self) -> serde_json::Value;
101Ôćĺ    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value>;
102Ôćĺ}
103Ôćĺ
104Ôćĺ#[async_trait]
105Ôćĺimpl McpAgentTool for McpToolBridge {
106Ôćĺ    fn name(&self) -> &str {
107Ôćĺ        &self.prefixed_name
108Ôćĺ    }
109Ôćĺ
110Ôćĺ    fn description(&self) -> &str {
111Ôćĺ        &self.description
112Ôćĺ    }
113Ôćĺ
114Ôćĺ    fn parameters_schema(&self) -> serde_json::Value {
115Ôćĺ        self.input_schema.clone()
116Ôćĺ    }
117Ôćĺ
118Ôćĺ    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value> {
119Ôćĺ        // Clean up arguments before forwarding to the MCP server:
120Ôćĺ        // 1. Strip internal metadata keys (e.g. _session_key) injected by the
121Ôćĺ        //    agent runner ÔÇö these break servers with strict validation.
122Ôćĺ        // 2. Strip null values ÔÇö these arise from strict-mode schema patching
123Ôćĺ        //    that makes optional properties nullable.  MCP servers expect
124Ôćĺ        //    optional fields to be absent, not null.
125Ôćĺ        let params = match params {
126Ôćĺ            serde_json::Value::Object(mut map) => {
127Ôćĺ                map.retain(|k, v| !k.starts_with('_') && !v.is_null());
128Ôćĺ                strip_nulls_recursive(&mut map);
129Ôćĺ                serde_json::Value::Object(map)
130Ôćĺ            },
131Ôćĺ            other => other,
132Ôćĺ        };
133Ôćĺ
134Ôćĺ        let client = self.client.read().await;
135Ôćĺ        let result = client.call_tool(&self.original_name, params).await?;
136Ôćĺ
137Ôćĺ        if result.is_error {
138Ôćĺ            let text = result
139Ôćĺ                .content
140Ôćĺ                .iter()
141Ôćĺ                .filter_map(|c| match c {
142Ôćĺ                    ToolContent::Text { text } => Some(text.as_str()),
143Ôćĺ                    _ => None,
144Ôćĺ                })
145Ôćĺ                .collect::<Vec<_>>()
146Ôćĺ                .join("\n");
147Ôćĺ            return Err(Error::message(format!("MCP tool error: {text}")));
148Ôćĺ        }
149Ôćĺ
150Ôćĺ        // Flatten text content into a single JSON value.

