178Ôćĺ    /// Start a single server connection.
179Ôćĺ    ///
180Ôćĺ    /// For SSE servers: attempts unauthenticated first. On 401 Unauthorized,
181Ôćĺ    /// stores auth context and returns `McpManagerError::OAuthRequired`.
182Ôćĺ    pub async fn start_server(&self, name: &str, config: &McpServerConfig) -> Result<()> {
183Ôćĺ        // Shut down existing connection if any.
184Ôćĺ        self.stop_server(name).await;
185Ôćĺ
186Ôćĺ        // Network work happens outside the lock.
187Ôćĺ        let (client, auth_provider) = match config.transport {
188Ôćĺ            TransportType::Sse | TransportType::StreamableHttp => {
189Ôćĺ                let env_overrides = {
190Ôćĺ                    let inner = self.inner.read().await;
191Ôćĺ                    inner.env_overrides.clone()
192Ôćĺ                };
193Ôćĺ                let remote = ResolvedRemoteConfig::from_server_config(config, &env_overrides)
194Ôćĺ                    .with_context(|| format!("SSE transport for '{name}' requires a url"))?;
195Ôćĺ
196Ôćĺ                // Check if we already have an auth provider (from a previous connection).
197Ôćĺ                let existing_auth = {
198Ôćĺ                    let inner = self.inner.read().await;
199Ôćĺ                    inner.auth_providers.get(name).cloned()
200Ôćĺ                };
201Ôćĺ
202Ôćĺ                let has_existing_auth_provider = existing_auth.is_some();
203Ôćĺ                let auth_provider = existing_auth.unwrap_or_else(|| {
204Ôćĺ                    Self::build_auth_provider(name, &remote, config.oauth.as_ref())
205Ôćĺ                });
206Ôćĺ
207Ôćĺ                // If we have a stored token, prefer auth transport immediately.
208Ôćĺ                // This avoids forced re-auth at process start for OAuth-backed servers.
209Ôćĺ                let has_stored_token = if has_existing_auth_provider {
210Ôćĺ                    false
211Ôćĺ                } else {
212Ôćĺ                    auth_provider.access_token().await?.is_some()
213Ôćĺ                };
214Ôćĺ
215Ôćĺ                if Self::should_attempt_auth_connection(
216Ôćĺ                    has_existing_auth_provider,
217Ôćĺ                    config.oauth.is_some(),
218Ôćĺ                    has_stored_token,
219Ôćĺ                ) {
220Ôćĺ                    let client = McpClient::connect_sse_with_auth(
221Ôćĺ                        name,
222Ôćĺ                        &remote,
223Ôćĺ                        auth_provider.clone(),
224Ôćĺ                        self.effective_timeout_for(config),
225Ôćĺ                    )
226Ôćĺ                    .await?;
227Ôćĺ                    (client, Some(auth_provider))
228Ôćĺ                } else {
229Ôćĺ                    // No hint that auth is needed yet, probe unauthenticated first.
230Ôćĺ                    match McpClient::connect_sse(name, &remote, self.effective_timeout_for(config))
231Ôćĺ                        .await
232Ôćĺ                    {
233Ôćĺ                        Ok(client) => (client, None),
234Ôćĺ                        Err(e) => {
235Ôćĺ                            // Check if it's a 401 Unauthorized.
236Ôćĺ                            if let Error::Transport(McpTransportError::Unauthorized {
237Ôćĺ                                www_authenticate,
238Ôćĺ                            }) = &e
239Ôćĺ                            {
240Ôćĺ                                info!(
241Ôćĺ                                    server = %name,
242Ôćĺ                                    "SSE server requires auth"
243Ôćĺ                                );
244Ôćĺ
245Ôćĺ                                // Mark auth as required and persist challenge metadata.
246Ôćĺ                                let auth_ok = auth_provider
247Ôćĺ                                    .handle_unauthorized(www_authenticate.as_deref())
248Ôćĺ                                    .await?;
249Ôćĺ
250Ôćĺ                                if !auth_ok {
251Ôćĺ                                    let mut inner = self.inner.write().await;
252Ôćĺ                                    inner.auth_providers.insert(name.to_string(), auth_provider);
253Ôćĺ                                    return Err(McpManagerError::OAuthRequired {
254Ôćĺ                                        server: name.to_string(),
255Ôćĺ                                    }
256Ôćĺ                                    .into());
257Ôćĺ                                }
258Ôćĺ
259Ôćĺ                                // Retry with auth.
260Ôćĺ                                let client = McpClient::connect_sse_with_auth(
261Ôćĺ                                    name,
262Ôćĺ                                    &remote,
263Ôćĺ                                    auth_provider.clone(),
264Ôćĺ                                    self.effective_timeout_for(config),
265Ôćĺ                                )
266Ôćĺ                                .await?;
267Ôćĺ                                (client, Some(auth_provider))
268Ôćĺ                            } else {
269Ôćĺ                                return Err(e);
270Ôćĺ                            }
271Ôćĺ                        },
272Ôćĺ                    }
273Ôćĺ                }
274Ôćĺ            },
275Ôćĺ            TransportType::Stdio => {
276Ôćĺ                let client = McpClient::connect(
277Ôćĺ                    name,
278Ôćĺ                    &config.command,
279Ôćĺ                    &config.args,
280Ôćĺ                    &config.env,
281Ôćĺ                    self.effective_timeout_for(config),
282Ôćĺ                )
283Ôćĺ                .await?;
284Ôćĺ                (client, None)
285Ôćĺ            },
286Ôćĺ        };
287Ôćĺ
288Ôćĺ        // Fetch tools.
289Ôćĺ        let mut client = client;
290Ôćĺ        let tool_defs = client.list_tools().await?.to_vec();
291Ôćĺ        info!(
292Ôćĺ            server = %name,
293Ôćĺ            tools = tool_defs.len(),
294Ôćĺ            "MCP server started with tools"
295Ôćĺ        );
296Ôćĺ
297Ôćĺ        // Atomic insert of client, tools, and auth provider.
298Ôćĺ        let client: Arc<RwLock<dyn McpClientTrait>> = Arc::new(RwLock::new(client));
299Ôćĺ        let mut inner = self.inner.write().await;
300Ôćĺ        inner.clients.insert(name.to_string(), client);
301Ôćĺ        inner.tools.insert(name.to_string(), tool_defs);
302Ôćĺ
303Ôćĺ        if let Some(auth) = auth_provider {
304Ôćĺ            inner.auth_providers.insert(name.to_string(), auth);
305Ôćĺ        }
306Ôćĺ
307Ôćĺ        Ok(())
308Ôćĺ    }
309Ôćĺ
310Ôćĺ    /// Stop a server connection.
311Ôćĺ    pub async fn stop_server(&self, name: &str) {
