313Ôćĺ        // Keep auth_providers for potential reconnection.
314Ôćĺ        let client = {
315Ôćĺ            let mut inner = self.inner.write().await;
316Ôćĺ            inner.tools.remove(name);
317Ôćĺ            inner.clients.remove(name)
