365Ôćĺ
366Ôćĺ        let existing_auth = {
367Ôćĺ            let inner = self.inner.read().await;
368Ôćĺ            inner.auth_providers.get(name).cloned()
369Ôćĺ        };
370Ôćĺ        let has_existing_auth_provider = existing_auth.is_some();
