393Ôćĺ            inner
394Ôćĺ                .auth_providers
395Ôćĺ                .iter()
396Ôćĺ                .map(|(name, provider)| (name.clone(), provider.clone()))
397Ôćĺ                .collect()
398Ôćĺ        };
399Ôćĺ
400Ôćĺ        for (name, provider) in providers {
