200Ôćĺ    fn parse_event_stream_response(body: &str, method: &str) -> Result<JsonRpcResponse> {
201Ôćĺ        let mut data = String::new();
202Ôćĺ
203Ôćĺ        for line in body.lines() {
204Ôćĺ            let trimmed = line.trim_end();
205Ôćĺ            if let Some(rest) = trimmed.strip_prefix("data:") {
206Ôćĺ                if !data.is_empty() {
207Ôćĺ                    data.push('\n');
208Ôćĺ                }
209Ôćĺ                data.push_str(rest.trim_start());
210Ôćĺ                continue;
211Ôćĺ            }
212Ôćĺ
213Ôćĺ            if trimmed.is_empty() && !data.is_empty() {
214Ôćĺ                if let Ok(resp) = serde_json::from_str::<JsonRpcResponse>(&data) {
215Ôćĺ                    return Ok(resp);
216Ôćĺ                }
217Ôćĺ                data.clear();
218Ôćĺ            }
219Ôćĺ        }
220Ôćĺ
221Ôćĺ        if !data.is_empty()
222Ôćĺ            && let Ok(resp) = serde_json::from_str::<JsonRpcResponse>(&data)
223Ôćĺ        {
224Ôćĺ            return Ok(resp);
225Ôćĺ        }
226Ôćĺ
227Ôćĺ        Err(Error::message(format!(
228Ôćĺ            "failed to parse JSON-RPC response from event stream for '{method}'"
229Ôćĺ        )))
230Ôćĺ    }
