232Ôćĺ    /// Send a POST request and handle 401 with auth retry.
233Ôćĺ    /// Returns the HTTP response or a typed `McpTransportError`.
234Ôćĺ    async fn send_with_auth_retry(
235Ôćĺ        &self,
236Ôćĺ        method: &str,
237Ôćĺ        body: &impl serde::Serialize,
238Ôćĺ    ) -> Result<reqwest::Response> {
239Ôćĺ        // First attempt
240Ôćĺ        let req = self.build_post().await?;
241Ôćĺ        let http_resp = req
242Ôćĺ            .json(body)
243Ôćĺ            .send()
244Ôćĺ            .await
245Ôćĺ            .map_err(sanitize_reqwest_error)
246Ôćĺ            .with_context(|| format!("SSE POST to '{}' for '{method}' failed", self.display_url))?;
247Ôćĺ
248Ôćĺ        if http_resp.status() == reqwest::StatusCode::UNAUTHORIZED {
249Ôćĺ            let has_session_header = http_resp.headers().contains_key(MCP_SESSION_ID_HEADER);
250Ôćĺ            self.store_session_id_from_response(&http_resp).await;
251Ôćĺ
252Ôćĺ            if let Some(auth) = &self.auth {
253Ôćĺ                let first_www_auth = http_resp
254Ôćĺ                    .headers()
255Ôćĺ                    .get("www-authenticate")
256Ôćĺ                    .and_then(|v| v.to_str().ok())
257Ôćĺ                    .map(String::from);
258Ôćĺ
259Ôćĺ                // Some streamable HTTP servers issue a session ID alongside 401
260Ôćĺ                // and expect subsequent requests to include it. Retry once with
261Ôćĺ                // current auth/session before forcing interactive re-auth.
262Ôćĺ                if has_session_header {
263Ôćĺ                    info!(
264Ôćĺ                        method = %method,
265Ôćĺ                        url = %self.display_url,
266Ôćĺ                        www_authenticate = ?first_www_auth,
267Ôćĺ                        "received 401 with session header, replaying request before OAuth re-auth"
268Ôćĺ                    );
269Ôćĺ
270Ôćĺ                    let req = self.build_post().await?;
271Ôćĺ                    let replay_resp = req
272Ôćĺ                        .json(body)
273Ôćĺ                        .send()
274Ôćĺ                        .await
275Ôćĺ                        .map_err(sanitize_reqwest_error)
276Ôćĺ                        .with_context(|| {
277Ôćĺ                            format!(
278Ôćĺ                                "SSE POST session replay to '{}' for '{method}' failed",
279Ôćĺ                                self.display_url
280Ôćĺ                            )
281Ôćĺ                        })?;
282Ôćĺ
283Ôćĺ                    if replay_resp.status() != reqwest::StatusCode::UNAUTHORIZED {
284Ôćĺ                        self.store_session_id_from_response(&replay_resp).await;
285Ôćĺ                        return Ok(replay_resp);
286Ôćĺ                    }
287Ôćĺ
288Ôćĺ                    self.store_session_id_from_response(&replay_resp).await;
289Ôćĺ                    let replay_www_auth = replay_resp
290Ôćĺ                        .headers()
291Ôćĺ                        .get("www-authenticate")
292Ôćĺ                        .and_then(|v| v.to_str().ok())
293Ôćĺ                        .map(String::from);
294Ôćĺ
295Ôćĺ                    info!(
296Ôćĺ                        method = %method,
297Ôćĺ                        url = %self.display_url,
298Ôćĺ                        "received 401 after session replay, attempting OAuth re-auth"
299Ôćĺ                    );
300Ôćĺ
301Ôćĺ                    if auth.handle_unauthorized(replay_www_auth.as_deref()).await? {
302Ôćĺ                        // Retry with new token
303Ôćĺ                        let req = self.build_post().await?;
304Ôćĺ                        let retry_resp = req
305Ôćĺ                            .json(body)
306Ôćĺ                            .send()
307Ôćĺ                            .await
308Ôćĺ                            .map_err(sanitize_reqwest_error)
309Ôćĺ                            .with_context(|| {
310Ôćĺ                                format!(
311Ôćĺ                                    "SSE POST retry to '{}' for '{method}' failed",
312Ôćĺ                                    self.display_url
313Ôćĺ                                )
314Ôćĺ                            })?;
315Ôćĺ
316Ôćĺ                        if retry_resp.status() == reqwest::StatusCode::UNAUTHORIZED {
317Ôćĺ                            return Err(McpTransportError::Unauthorized {
318Ôćĺ                                www_authenticate: retry_resp
319Ôćĺ                                    .headers()
320Ôćĺ                                    .get("www-authenticate")
321Ôćĺ                                    .and_then(|v| v.to_str().ok())
322Ôćĺ                                    .map(String::from),
323Ôćĺ                            }
324Ôćĺ                            .into());
325Ôćĺ                        }
326Ôćĺ
327Ôćĺ                        self.store_session_id_from_response(&retry_resp).await;
328Ôćĺ                        return Ok(retry_resp);
329Ôćĺ                    }
330Ôćĺ
331Ôćĺ                    return Err(McpTransportError::Unauthorized {
332Ôćĺ                        www_authenticate: replay_www_auth,
333Ôćĺ                    }
334Ôćĺ                    .into());
335Ôćĺ                }
336Ôćĺ
337Ôćĺ                info!(
338Ôćĺ                    method = %method,
339Ôćĺ                    url = %self.display_url,
340Ôćĺ                    www_authenticate = ?first_www_auth,
341Ôćĺ                    "received 401, attempting OAuth re-auth"
342Ôćĺ                );
343Ôćĺ
344Ôćĺ                if auth.handle_unauthorized(first_www_auth.as_deref()).await? {
345Ôćĺ                    // Retry with new token
346Ôćĺ                    let req = self.build_post().await?;
347Ôćĺ                    let retry_resp = req
348Ôćĺ                        .json(body)
349Ôćĺ                        .send()
350Ôćĺ                        .await
351Ôćĺ                        .map_err(sanitize_reqwest_error)
352Ôćĺ                        .with_context(|| {
353Ôćĺ                            format!(
354Ôćĺ                                "SSE POST retry to '{}' for '{method}' failed",
355Ôćĺ                                self.display_url
356Ôćĺ                            )
357Ôćĺ                        })?;
358Ôćĺ
359Ôćĺ                    if retry_resp.status() == reqwest::StatusCode::UNAUTHORIZED {
360Ôćĺ                        return Err(McpTransportError::Unauthorized {
361Ôćĺ                            www_authenticate: retry_resp
362Ôćĺ                                .headers()
363Ôćĺ                                .get("www-authenticate")
364Ôćĺ                                .and_then(|v| v.to_str().ok())
365Ôćĺ                                .map(String::from),
366Ôćĺ                        }
367Ôćĺ                        .into());
368Ôćĺ                    }
369Ôćĺ
370Ôćĺ                    self.store_session_id_from_response(&retry_resp).await;
371Ôćĺ                    return Ok(retry_resp);
372Ôćĺ                }
373Ôćĺ            }
374Ôćĺ
375Ôćĺ            // No auth provider or auth failed
376Ôćĺ            return Err(McpTransportError::Unauthorized {
377Ôćĺ                www_authenticate: http_resp
378Ôćĺ                    .headers()
379Ôćĺ                    .get("www-authenticate")
380Ôćĺ                    .and_then(|v| v.to_str().ok())
381Ôćĺ                    .map(String::from),
382Ôćĺ            }
383Ôćĺ            .into());
384Ôćĺ        }
385Ôćĺ
386Ôćĺ        self.store_session_id_from_response(&http_resp).await;
387Ôćĺ        Ok(http_resp)
388Ôćĺ    }
389Ôćĺ}
