391Ôćĺ#[async_trait::async_trait]
392Ôćĺimpl McpTransport for SseTransport {
393Ôćĺ    async fn request(
394Ôćĺ        &self,
395Ôćĺ        method: &str,
396Ôćĺ        params: Option<serde_json::Value>,
397Ôćĺ    ) -> Result<JsonRpcResponse> {
398Ôćĺ        let id = self.next_id.fetch_add(1, Ordering::SeqCst);
399Ôćĺ        let req = JsonRpcRequest::new(id, method, params);
400Ôćĺ
401Ôćĺ        debug!(method = %method, id = %id, url = %self.display_url, "SSE client -> server");
402Ôćĺ
403Ôćĺ        let http_resp = self.send_with_auth_retry(method, &req).await?;
404Ôćĺ
405Ôćĺ        if !http_resp.status().is_success() {
406Ôćĺ            let status = http_resp.status();
407Ôćĺ            let body = http_resp.text().await.unwrap_or_default();
408Ôćĺ            return Err(Error::message(format!(
409Ôćĺ                "MCP SSE server returned HTTP {status} for '{method}': {body}"
410Ôćĺ            )));
411Ôćĺ        }
412Ôćĺ
413Ôćĺ        let resp: JsonRpcResponse = if Self::response_is_event_stream(&http_resp) {
414Ôćĺ            let body = http_resp
415Ôćĺ                .text()
416Ôćĺ                .await
417Ôćĺ                .with_context(|| format!("failed to read event stream response for '{method}'"))?;
418Ôćĺ            Self::parse_event_stream_response(&body, method)?
419Ôćĺ        } else {
420Ôćĺ            http_resp
421Ôćĺ                .json()
422Ôćĺ                .await
423Ôćĺ                .with_context(|| format!("failed to parse JSON-RPC response for '{method}'"))?
424Ôćĺ        };
425Ôćĺ
426Ôćĺ        if let Some(ref err) = resp.error {
427Ôćĺ            return Err(Error::message(format!(
428Ôćĺ                "MCP SSE error on '{method}': code={} message={}",
429Ôćĺ                err.code, err.message
430Ôćĺ            )));
431Ôćĺ        }
432Ôćĺ
433Ôćĺ        Ok(resp)
434Ôćĺ    }
