436Ôćĺ    async fn notify(&self, method: &str, params: Option<serde_json::Value>) -> Result<()> {
437Ôćĺ        let notif = JsonRpcNotification {
438Ôćĺ            jsonrpc: "2.0".into(),
439Ôćĺ            method: method.into(),
440Ôćĺ            params,
441Ôćĺ        };
442Ôćĺ
443Ôćĺ        debug!(
444Ôćĺ            method = %method,
445Ôćĺ            url = %self.display_url,
446Ôćĺ            "SSE client -> server (notification)"
447Ôćĺ        );
448Ôćĺ
449Ôćĺ        let http_resp = self.send_with_auth_retry(method, &notif).await?;
450Ôćĺ
451Ôćĺ        if !http_resp.status().is_success() {
452Ôćĺ            let status = http_resp.status();
453Ôćĺ            warn!(method = %method, %status, "SSE notification returned non-success");
454Ôćĺ        }
