459Ôćĺ    async fn is_alive(&self) -> bool {
460Ôćĺ        // Try a lightweight GET request to check connectivity and session continuity.
461Ôćĺ        let mut req = self
462Ôćĺ            .client
463Ôćĺ            .get(self.request_url.expose_secret())
464Ôćĺ            .timeout(std::time::Duration::from_secs(5))
465Ôćĺ            .header("Accept", STREAMABLE_ACCEPT_HEADER)
466Ôćĺ            .header(MCP_PROTOCOL_VERSION_HEADER, PROTOCOL_VERSION);
467Ôćĺ
468Ôćĺ        req = self.apply_default_headers(req);
469Ôćĺ
470Ôćĺ        if let Some(session_id) = self.session_id.read().await.clone() {
471Ôćĺ            req = req.header(MCP_SESSION_ID_HEADER, session_id);
472Ôćĺ        }
473Ôćĺ
474Ôćĺ        // Include auth header in health checks too
475Ôćĺ        if let Some(token) = match &self.auth {
476Ôćĺ            Some(auth) => auth.access_token().await.ok().flatten(),
477Ôćĺ            None => None,
478Ôćĺ        } {
479Ôćĺ            req = req.header("Authorization", format!("Bearer {}", token.expose_secret()));
480Ôćĺ        }
481Ôćĺ
482Ôćĺ        match req.send().await {
483Ôćĺ            Ok(resp) => {
484Ôćĺ                self.store_session_id_from_response(&resp).await;
485Ôćĺ                if resp.status() == reqwest::StatusCode::UNAUTHORIZED {
486Ôćĺ                    return true;
487Ôćĺ                }
488Ôćĺ                // Any successful response means the server is reachable ÔÇö
489Ôćĺ                // Streamable HTTP servers may reply with application/json
490Ôćĺ                // rather than text/event-stream, which is equally valid.
491Ôćĺ                resp.status().is_success()
492Ôćĺ            },
493Ôćĺ            Err(_) => false,
494Ôćĺ        }
495Ôćĺ    }
496Ôćĺ
497Ôćĺ    async fn kill(&self) {
498Ôćĺ        let session_id = {
499Ôćĺ            let mut slot = self.session_id.write().await;
500Ôćĺ            slot.take()
501Ôćĺ        };
502Ôćĺ
503Ôćĺ        let Some(session_id) = session_id else {
504Ôćĺ            return;
505Ôćĺ        };
506Ôćĺ
507Ôćĺ        let mut req = self
508Ôćĺ            .client
509Ôćĺ            .delete(self.request_url.expose_secret())
510Ôćĺ            .timeout(std::time::Duration::from_secs(5))
511Ôćĺ            .header(MCP_PROTOCOL_VERSION_HEADER, PROTOCOL_VERSION)
512Ôćĺ            .header(MCP_SESSION_ID_HEADER, session_id);
513Ôćĺ
514Ôćĺ        req = self.apply_default_headers(req);
515Ôćĺ
516Ôćĺ        if let Some(token) = match &self.auth {
517Ôćĺ            Some(auth) => auth.access_token().await.ok().flatten(),
518Ôćĺ            None => None,
519Ôćĺ        } {
520Ôćĺ            req = req.header("Authorization", format!("Bearer {}", token.expose_secret()));
521Ôćĺ        }
522Ôćĺ
523Ôćĺ        if let Err(e) = req.send().await {
524Ôćĺ            warn!(
525Ôćĺ                url = %self.display_url,
526Ôćĺ                error = %sanitize_reqwest_error(e),
527Ôćĺ                "failed to close MCP streamable HTTP session"
528Ôćĺ            );
529Ôćĺ        }
530Ôćĺ    }
531Ôćĺ}
